    loadWorkspaceFiles();
  }, [loadWorkspaceFiles]);

  return {
    isOpen: Boolean(range),
    query: range?.query ?? "",
    flatOptions,
    sections,
    activeIndex,
    setActiveIndex,
    handleTextChange,
    handleCaretChange,
    handleKeyDown,
    selectOption,
    closeMenu,
    workspaceStatus,
    workspaceError,
    retryWorkspace,
  };
};

