            ? flatOptions.length - 1
            : (previous - 1) % flatOptions.length,
        );
        return;
      }

      if (event.key === "Enter" || event.key === "Tab") {
        if (flatOptions.length === 0) {
          return;
        }
        event.preventDefault();
        selectOption();
        return;
      }

      if (event.key === "Escape") {
        event.preventDefault();
        closeMenu();
      }
    },
    [range, flatOptions, selectOption, closeMenu],
  );

  const retryWorkspace = useCallback(() => {
    loadWorkspaceFiles();
  }, [loadWorkspaceFiles]);

  return {
    isOpen: Boolean(range),
    query: range?.query ?? "",
    flatOptions,
    sections,
    activeIndex,
    setActiveIndex,
    handleTextChange,
    handleCaretChange,
    handleKeyDown,
    selectOption,
    closeMenu,
    workspaceStatus,
    workspaceError,
    retryWorkspace,
  };
};

